#!/usr/bin/env node
import {Command} from 'commander';
import type {Command as Commander} from 'commander';
import {createInterface} from 'node:readline';
import {
	loadConfig,
	mergeConfig,
	defaultConfigPath,
	type Config,
	type PartialConfig,
} from './config.js';
import {envOverrides} from './env-config.js';
import {scan} from './scan.js';
import {remoteAdd, remoteRm, listMirrors, RegistryError} from './registry.js';
import {findParticipatingRepos} from './detect.js';
import {formatReport} from './format.js';
import {runOnce, type ItemResult} from './run.js';
import {performClaim} from './claim-cas.js';
import {performStart} from './start.js';
import {
	performWorkOn,
	loadHumanWorktreesDir,
	persistHumanWorktreesDir,
} from './work-on.js';
import {performComplete, integrationFromFlags} from './complete.js';
import {performDo} from './do.js';
import {createHarness} from './pi-harness.js';
import {shouldUseColor} from './output.js';
import {resolveRepoConfig} from './repo-config.js';
import {runVerify} from './verify.js';
import {renderPrompt} from './prompt.js';
import {gc, RETAIN_REASON_TEXT} from './gc.js';
import {status, formatStatus} from './status.js';
import {ledgerWrite} from './ledger-write.js';
import {arbiterStatus, DEFAULT_ARBITER_REMOTE} from './arbiter.js';
import {resolveSliceOnlyArg, SlugResolutionError} from './slug-namespace.js';

interface ScanFlags {
	config?: string;
	allowAgents?: boolean;
	json?: boolean;
}

/**
 * Whether `--allow-agents` / `--no-allow-agents` was explicitly passed on the
 * command line. Commander gives a negatable boolean option a default of `true`,
 * so we must check the value SOURCE to distinguish "user set it" from "default";
 * only an explicit flag becomes a config override (so config/defaults still win
 * otherwise).
 */
function allowAgentsFromCli(
	command: Commander | undefined,
): boolean | undefined {
	if (!command) {
		return undefined;
	}
	const source = command.getOptionValueSource('allowAgents');
	if (source !== 'cli') {
		return undefined;
	}
	return command.getOptionValue('allowAgents') as boolean;
}

/**
 * Build the overrides a user supplied via CLI flags. Discovery is the registry
 * (the hub-mirror set, ADR §1), so there are no `--root`/`--include`/`--exclude`
 * flags any more — only the autonomy-gate `--allow-agents` toggle.
 */
function flagOverrides(flags: ScanFlags, command?: Commander): PartialConfig {
	const overrides: PartialConfig = {};
	const allowAgents = allowAgentsFromCli(command);
	if (allowAgents !== undefined) {
		overrides.allowAgents = allowAgents;
	}
	return overrides;
}

/**
 * Resolve the global (non-per-repo) config along the chain
 *
 *   flag > ENV (AGENT_RUNNER_*) > global file > built-in default
 *
 * by layering the file config, then the `AGENT_RUNNER_*` env layer, then the
 * flag overrides on top. Env is a per-machine source (like a flag or the global
 * file) and may set ANY key, host-only included. Used by the commands that build
 * a single global config (`scan`, `run`); per-repo commands fold env in via
 * `resolveRepoConfig` instead.
 */
function resolveGlobalConfig(
	fileConfig: PartialConfig,
	flags: PartialConfig,
): Config {
	return mergeConfig({...fileConfig, ...envOverrides(), ...flags});
}

/**
 * First-use prompt for the human worktree root (`work-on`). Offers `suggestion`
 * as the default (Enter accepts it); a blank non-interactive answer aborts. The
 * prompt goes to stderr so `--print-dir`'s stdout stays clean.
 */
function promptForWorktreesRoot(suggestion: string): Promise<string> {
	return new Promise((resolvePrompt) => {
		const rl = createInterface({input: process.stdin, output: process.stderr});
		rl.question(
			'work-on needs a human worktree root (NOT under ~/.agent-runner). ' +
				`Where should parallel worktrees live? [${suggestion}] `,
			(answer) => {
				rl.close();
				const trimmed = answer.trim();
				resolvePrompt(trimmed === '' ? suggestion : trimmed);
			},
		);
	});
}

interface RunFlags extends ScanFlags {
	once?: boolean;
	maxParallel?: string;
	perRepoMax?: string;
	arbiter?: string;
	integration?: string;
	provider?: string;
	agentCmd?: string;
	model?: string;
	harness?: string;
	piBin?: string;
	workspace?: string;
}

function runFlagOverrides(flags: RunFlags, command?: Commander): PartialConfig {
	const overrides = flagOverrides(flags, command);
	if (flags.maxParallel !== undefined) {
		overrides.maxParallel = Number(flags.maxParallel);
	}
	if (flags.perRepoMax !== undefined) {
		overrides.perRepoMax = Number(flags.perRepoMax);
	}
	if (flags.arbiter !== undefined) {
		overrides.defaultArbiter = flags.arbiter;
	}
	if (flags.integration === 'propose' || flags.integration === 'merge') {
		overrides.integration = flags.integration;
	}
	if (flags.provider === 'github' || flags.provider === 'none') {
		overrides.provider = flags.provider;
	}
	if (flags.agentCmd !== undefined) {
		overrides.agentCmd = flags.agentCmd;
	}
	if (flags.model !== undefined) {
		overrides.model = flags.model;
	}
	if (flags.harness === 'null' || flags.harness === 'pi') {
		overrides.harness = flags.harness;
	}
	if (flags.piBin !== undefined) {
		overrides.piBin = flags.piBin;
	}
	return overrides;
}

function formatItemLine(item: ItemResult): string {
	const extra = item.detail ? ` — ${item.detail}` : '';
	return `  [${item.status}] ${item.repoPath} :: ${item.slug}${extra}`;
}

interface ClaimFlags {
	arbiter?: string;
	by?: string;
	retries?: string;
	dryRun?: boolean;
	force?: boolean;
	ignoreNotReady?: boolean;
}

interface VerifyFlags {
	config?: string;
}

interface StartFlags {
	arbiter?: string;
	by?: string;
	resume?: boolean;
	force?: boolean;
	ignoreNotReady?: boolean;
}

interface WorkOnFlags {
	config?: string;
	arbiter?: string;
	by?: string;
	copy?: string;
	copyFrom?: string;
	force?: boolean;
	ignoreNotReady?: boolean;
	printDir?: boolean;
	workspace?: string;
}

interface CompleteFlags {
	config?: string;
	arbiter?: string;
	merge?: boolean;
	propose?: boolean;
	switch?: boolean;
	skipVerify?: boolean;
	type?: string;
	message?: string;
}

interface DoFlags {
	config?: string;
	arbiter?: string;
	merge?: boolean;
	propose?: boolean;
	agentCmd?: string;
	model?: string;
	harness?: string;
	piBin?: string;
	watch?: boolean;
}

interface GcFlags {
	config?: string;
	workspace?: string;
	force?: boolean;
	yes?: boolean;
	json?: boolean;
}

interface StatusFlags {
	config?: string;
	workspace?: string;
	arbiterRemote?: string;
	noArbiter?: boolean;
	json?: boolean;
}

interface ReturnFlags {
	config?: string;
	cwd?: string;
	arbiter?: string;
}

interface RemoteAddFlags {
	config?: string;
	local?: boolean;
	arbiterRemote?: string;
	force?: boolean;
}

interface RemoteRmFlags {
	config?: string;
}

interface RemoteLsFlags {
	config?: string;
	json?: boolean;
}

interface RemoteFindFlags {
	config?: string;
	yes?: boolean;
}

/**
 * Resolve a slice-only command's slug argument through the §3a namespace guard
 * (`resolveSliceOnlyArg`): accept bare (= slice) + `slice:` (explicit alias),
 * REJECT `prd:` with a clear "operates on slices, not PRDs" error. On rejection
 * it prints the error to stderr and exits 1 (the slice-only commands never act
 * on a PRD). An OMITTED slug (`start`/`complete`/`prompt` infer it from the
 * branch) passes through untouched.
 *
 * `do` is the ONE command that spans both namespaces; it consumes the full
 * `resolveSlug` (with the cross-namespace collision check) in the `do-in-place`
 * slice. This guard is the slice-only half of ADR §3a.
 */
function resolveSliceOnlySlug(slug: string | undefined): string | undefined {
	if (slug === undefined) {
		return undefined;
	}
	try {
		return resolveSliceOnlyArg(slug);
	} catch (err) {
		if (err instanceof SlugResolutionError) {
			console.error(`error: ${err.message}`);
			process.exit(1);
		}
		throw err;
	}
}

export function buildProgram(): Command {
	const program = new Command();

	program
		.name('agent-runner')
		.description('Autonomous parallel agents over file-based work/ queues.');

	program
		.command('scan')
		.description(
			'Read-only: list the cross-repo queue of work items (across the registered hub mirrors) and whether each is runnable now. Discovery is the registry — the hub-mirror set under workspacesDir/repos/ (no --root/roots).',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--allow-agents',
			'allow agents to claim undeclared (not humanOnly) slices',
		)
		.option(
			'--no-allow-agents',
			'forbid agents from claiming undeclared slices (default)',
		)
		.option('--json', 'output the raw report as JSON')
		.action(async (flags: ScanFlags, command: Commander) => {
			const fileConfig = loadConfig(flags.config);
			const config = resolveGlobalConfig(
				fileConfig,
				flagOverrides(flags, command),
			);
			const report = await scan(config);
			if (flags.json) {
				console.log(
					JSON.stringify(
						report,
						(_key, value) => (value instanceof Set ? [...value] : value),
						2,
					),
				);
			} else {
				console.log(formatReport(report));
			}
		});

	program
		.command('run')
		.description(
			'Claim up to maxParallel eligible items, run the agent on each in isolation, integrate, then stop.',
		)
		.option('--once', 'run a single supervised tick then stop (increment B)')
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--allow-agents',
			'allow agents to claim undeclared (not humanOnly) slices',
		)
		.option(
			'--no-allow-agents',
			'forbid agents from claiming undeclared slices (default)',
		)
		.option('--max-parallel <n>', 'global cap on items claimed+run this tick')
		.option('--per-repo-max <n>', 'per-repo cap on concurrent claims')
		.option('--arbiter <remote>', 'name of the arbiter git remote')
		.option(
			'--integration <mode>',
			'integration mode: propose (default) or merge',
		)
		.option(
			'--provider <name>',
			'propose-mode review-request provider: github (gh pr create) or none (push-only). Default: auto-detect from the arbiter URL (a GitHub remote => github, else none).',
		)
		.option('--agent-cmd <cmd>', 'command to run one agent on a slice prompt')
		.option(
			'--model <id>',
			'model the agent runs on (routing intent; auth/keys stay the harness\u2019s job). pi: passed as --model; null/shell: substitutes a {model} placeholder in agentCmd. Resolved flag > env > per-repo > global > default (unset).',
		)
		.option(
			'--harness <adapter>',
			'harness adapter that launches the agent + reports liveness: null (default, shells out to agentCmd) or pi (the pi CLI)',
		)
		.option(
			'--pi-bin <path>',
			'pi CLI binary the pi harness invokes (default: pi on PATH)',
		)
		.option(
			'--workspace <dir>',
			'execution working area for hub mirrors + job worktrees (default: workspacesDir / ~/.agent-runner)',
		)
		.option('--json', 'output the raw result as JSON')
		.action(async (flags: RunFlags, command: Commander) => {
			if (!flags.once) {
				throw new Error(
					'only `run --once` is implemented (increment B). Pass --once.',
				);
			}
			const fileConfig = loadConfig(flags.config);
			const config = resolveGlobalConfig(
				fileConfig,
				runFlagOverrides(flags, command),
			);
			// The null adapter shells out to agentCmd, so it is required there; the
			// pi adapter invokes the pi CLI directly and does not consume agentCmd.
			if (config.harness !== 'pi' && config.agentCmd.trim() === '') {
				throw new Error(
					'no agentCmd configured — set `agentCmd` in config or pass --agent-cmd.',
				);
			}
			const workspace = flags.workspace ?? config.workspacesDir;
			const result = await runOnce({
				config,
				workspace,
				onWarn: (message) => console.error(`>> ${message}`),
			});
			if (flags.json) {
				console.log(JSON.stringify(result, null, 2));
			} else {
				for (const item of result.items) {
					console.log(formatItemLine(item));
				}
				console.log(
					`Summary: ${result.claimedAndDone} done, ${result.skipped} skipped, ${result.failed} failed.`,
				);
			}
		});

	program
		.command('verify')
		.description(
			"Run the repo's declared acceptance gate (per-repo `verify` config) and exit with its status (0 = pass). Deterministic shell gate; no model. Read-only with respect to work/.",
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.action(async (flags: VerifyFlags) => {
			const config = resolveGlobalConfig(loadConfig(flags.config), {});
			const result = await runVerify({
				cwd: process.cwd(),
				verify: config.verify,
			});
			process.exit(result.exitCode);
		});

	program
		.command('claim')
		.description(
			'Atomically claim a work/backlog/<slug>.md item via a compare-and-swap push to the arbiter (in-process; mirrors scripts/claim.sh).',
		)
		.argument('<slug>', 'the slug of the backlog item to claim')
		.option(
			'--arbiter <remote>',
			'name of the arbiter git remote (default: origin)',
			'origin',
		)
		.option('--by <who>', 'advisory claimer id (default: git user.name)')
		.option('--retries <n>', 'cap on push retries when main advances', '3')
		.option('--dry-run', 'show the intended push without mutating the arbiter')
		.option(
			'--force',
			'override the readiness guard: claim despite an unmet blockedBy, and silence the needsAnswers warning (loud, never default)',
		)
		.option(
			'--ignore-not-ready',
			'alias of --force for the readiness guard override',
		)
		.action(async (rawSlug: string, flags: ClaimFlags) => {
			// Slice-only command (§3a): accept bare + `slice:`, reject `prd:`.
			const slug = resolveSliceOnlySlug(rawSlug) as string;
			const result = await performClaim({
				slug,
				cwd: process.cwd(),
				arbiter: flags.arbiter ?? 'origin',
				by: flags.by,
				retries:
					flags.retries !== undefined ? Number(flags.retries) : undefined,
				dryRun: flags.dryRun,
				humanPath: true,
				override: flags.force === true || flags.ignoreNotReady === true,
				note: (message) => console.error(`>> ${message}`),
			});
			if (result.exitCode !== 0) {
				console.error(`error: ${result.message}`);
			}
			process.exit(result.exitCode);
		});

	program
		.command('start')
		.description(
			'Claim a backlog item (only if needed) and onboard onto its work/<slug> branch in the CURRENT checkout. Decides on the folder on <arbiter>/main, never on a frontmatter field. Launches no agent/editor.',
		)
		.argument(
			'[slug]',
			'the slug to start (inferred from a work/<slug> branch if omitted)',
		)
		.option(
			'--arbiter <remote>',
			'name of the arbiter git remote (default: origin)',
			'origin',
		)
		.option('--by <who>', 'advisory claimer id forwarded to the claim CAS')
		.option(
			'--resume',
			'assert ownership of an already in-progress item: switch to its work branch without claiming',
		)
		.option(
			'--force',
			'override the readiness guard: claim despite an unmet blockedBy, and silence the needsAnswers warning (loud, never default)',
		)
		.option(
			'--ignore-not-ready',
			'alias of --force for the readiness guard override',
		)
		.action(async (rawSlug: string | undefined, flags: StartFlags) => {
			// Slice-only command (§3a): accept bare + `slice:`, reject `prd:`.
			const slug = resolveSliceOnlySlug(rawSlug);
			const result = await performStart({
				slug,
				cwd: process.cwd(),
				arbiter: flags.arbiter ?? 'origin',
				by: flags.by,
				resume: flags.resume,
				override: flags.force === true || flags.ignoreNotReady === true,
				note: (message) => console.error(`>> ${message}`),
			});
			if (result.exitCode !== 0) {
				console.error(`error: ${result.message}`);
			}
			process.exit(result.exitCode);
		});

	program
		.command('work-on')
		.description(
			'HUMAN command: claim a slice and create an isolated worktree in a human-friendly location (under config humanWorktreesDir, NEVER ~/.agent-runner) for parallel work. Two forms: `work-on <slug>` (infer the arbiter from the current repo) and `work-on <remote> <slug>` (ensure a hub mirror via repo-mirror, creating if absent). BOTH claim, then always fetch + branch work/<slug> off the freshly-fetched <arbiter>/main — same claim, same starting commit; only the worktree LOCATION differs. --copy <patterns> copies named gitignored files (copy, not symlink; --copy-from required in remote mode) with a security notice. A binary cannot cd your shell: it prints the path + a cd hint; --print-dir emits the path only, for `work-on(){ cd "$(agent-runner work-on "$@" --print-dir)"; }`.',
		)
		.argument(
			'<remoteOrSlug>',
			'the slug (in-repo form) OR the remote (when a second slug arg follows)',
		)
		.argument(
			'[slug]',
			'the slug, when the first argument is a <remote> (remote form)',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--arbiter <remote>',
			'name of the arbiter git remote in the current repo (in-repo form; default: origin)',
			'origin',
		)
		.option('--by <who>', 'advisory claimer id forwarded to the claim CAS')
		.option(
			'--copy <patterns>',
			'comma-separated gitignored filenames to COPY into the worktree (e.g. .env.local,.env). In-repo: from the current repo; remote: requires --copy-from. Copy, not symlink.',
		)
		.option(
			'--copy-from <path>',
			'source dir for --copy in the remote form (required there; there is no implicit current repo)',
		)
		.option(
			'--print-dir',
			'print ONLY the worktree path to stdout (for a shell wrapper: work-on(){ cd "$(agent-runner work-on "$@" --print-dir)"; })',
		)
		.option(
			'--workspace <dir>',
			'execution working area for hub mirrors (default: workspacesDir / ~/.agent-runner)',
		)
		.option(
			'--force',
			'override the readiness guard: claim despite an unmet blockedBy, and silence the needsAnswers warning (loud, never default)',
		)
		.option(
			'--ignore-not-ready',
			'alias of --force for the readiness guard override',
		)
		.action(
			async (
				remoteOrSlug: string,
				slug: string | undefined,
				flags: WorkOnFlags,
			) => {
				// Disambiguate the two forms positionally: one arg ⇒ in-repo `<slug>`;
				// two args ⇒ remote `<remote> <slug>`.
				const remote = slug !== undefined ? remoteOrSlug : undefined;
				const rawSlug = slug !== undefined ? slug : remoteOrSlug;
				// Slice-only command (§3a): accept bare + `slice:`, reject `prd:`.
				const theSlug = resolveSliceOnlySlug(rawSlug) as string;

				const configPath = flags.config ?? defaultConfigPath();
				const {dir: configuredRoot, config} = loadHumanWorktreesDir(configPath);
				const workspace = flags.workspace ?? config.workspacesDir;

				// --print-dir wants a clean stdout, so all human-facing notes go to
				// stderr; the path is the ONLY thing on stdout (printed below).
				const printDir = flags.printDir === true;
				const result = await performWorkOn({
					slug: theSlug,
					remote,
					cwd: process.cwd(),
					arbiter: flags.arbiter ?? 'origin',
					by: flags.by,
					copy: flags.copy,
					copyFrom: flags.copyFrom,
					override: flags.force === true || flags.ignoreNotReady === true,
					workspacesDir: workspace,
					humanWorktreesDir: configuredRoot,
					promptForRoot: (suggestion) => promptForWorktreesRoot(suggestion),
					saveRoot: (chosen) => persistHumanWorktreesDir(chosen, configPath),
					note: (message) => console.error(`>> ${message}`),
				});
				if (result.exitCode !== 0) {
					console.error(`error: ${result.message}`);
					process.exit(result.exitCode);
				}
				if (printDir) {
					// Path only on stdout, so `cd "$(... --print-dir)"` works.
					process.stdout.write(`${result.dir}\n`);
				}
				process.exit(0);
			},
		);

	program
		.command('prompt')
		.description(
			"Print to stdout the work-agent prompt for a slice: the canonical CLAIM-PROTOCOL wrapper + the slice's own ## Prompt (with <slug> and source PRD substituted). Resolves work/in-progress/<slug>.md then work/backlog/<slug>.md; infers <slug> from a work/<slug> branch when omitted. Read-only, stdout only — the same assembly the autonomous runner feeds agentCmd.",
		)
		.argument(
			'[slug]',
			'the slug to render (inferred from a work/<slug> branch if omitted)',
		)
		.action((rawSlug: string | undefined) => {
			// Slice-only command (§3a): accept bare + `slice:`, reject `prd:`.
			const slug = resolveSliceOnlySlug(rawSlug);
			const output = renderPrompt({slug, cwd: process.cwd()});
			process.stdout.write(output);
		});

	program
		.command('complete')
		.description(
			'On a work/<slug> branch (slug inferred if omitted): run the gate, mark done (git mv in-progress\u2192done), commit (<type>(<slug>): <summary>; done) the agent\u2019s uncommitted work + the move, rebase onto <arbiter>/main, and integrate. Mode resolved at completion time (--merge/--propose > per-repo > global > default propose): merge\u2192push to main + switch+ff local main; propose\u2192push branch + switch to main (no ff). Then delete the LOCAL work branch iff provably on the arbiter (never the remote); --no-switch stays on the branch and keeps it. Never --force.',
		)
		.argument(
			'[slug]',
			'the slug to complete (inferred from a work/<slug> branch if omitted)',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--arbiter <remote>',
			'name of the arbiter git remote (default: origin)',
			'origin',
		)
		.option(
			'--merge',
			'integrate in merge mode this invocation (mutually exclusive with --propose; overrides config)',
		)
		.option(
			'--propose',
			'integrate in propose mode this invocation (mutually exclusive with --merge; overrides config)',
		)
		.option(
			'--no-switch',
			'stay on the work/<slug> branch (and keep it) instead of switching back to main',
		)
		.option(
			'--skip-verify',
			'skip the acceptance gate (human-only escape hatch; the runner never skips)',
		)
		.option('--type <type>', 'conventional-commit type for the commit', 'feat')
		.option(
			'--message <summary>',
			'commit summary (default: the slice title, minus a leading "slug \u2014 " prefix)',
		)
		.action(async (rawSlug: string | undefined, flags: CompleteFlags) => {
			// Slice-only command (§3a): accept bare + `slice:`, reject `prd:`.
			const slug = resolveSliceOnlySlug(rawSlug);
			const cwd = process.cwd();
			const global = loadConfig(flags.config);
			// Resolve the integration mode at completion time, highest first:
			//   --merge/--propose flag > per-repo .agent-runner.json > global > default.
			// The flag sits at the TOP of the same chain the autonomous runner uses
			// (per-repo > global > default), so human and autonomous paths agree.
			const flagMode = integrationFromFlags(flags);
			const resolved = resolveRepoConfig({
				repoPath: cwd,
				global,
				flags: flagMode ? {integration: flagMode} : {},
			});
			if (resolved.message) {
				console.error(`>> ${resolved.message}`);
			}
			const config = resolved.config;
			const result = await performComplete({
				slug,
				cwd,
				arbiter: flags.arbiter ?? config.defaultArbiter,
				integration: config.integration,
				provider: config.provider,
				noSwitch: flags.switch === false,
				verify: config.verify,
				skipVerify: flags.skipVerify,
				type: flags.type,
				message: flags.message,
				// Color the propose-mode next-step block only on an interactive
				// stdout TTY (and not under NO_COLOR); plain when piped/redirected.
				color: shouldUseColor(process.stdout),
				note: (message) => console.error(`>> ${message}`),
				// The propose next-step block is printed verbatim (no `>> ` prefix)
				// so its blank lines + heading stand out as the human call-to-action.
				noteBlock: (message) => console.error(message),
			});
			if (result.exitCode !== 0) {
				console.error(`error: ${result.message}`);
			}
			process.exit(result.exitCode);
		});

	program
		.command('do')
		.description(
			'The per-repo, in-place WORKER (the CI command): in the CURRENT checkout, refuse on a dirty tree, then claim + onboard onto work/<slug>, run the agent, gate, integrate in-place, and exit. do <slug> | do slice:<slug> | do prd:<slug> (the slicing path, not yet wired). --propose (default) / --merge resolved at integrate-time. Supersedes ar-run.sh. (do --remote is the do-remote slice; auto-pick / -n is do-autopick.)',
		)
		// EXTENSIBLE argument grammar (the three do-* slices grow this one block): a
		// single named item here, optional so do-autopick can widen it to variadic /
		// auto-pick without tearing it up. This slice uses EXACTLY one arg.
		.argument(
			'[slug]',
			'the item to do: bare (= the slice), slice:<slug>, or prd:<slug> (slice the PRD)',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--arbiter <remote>',
			'name of the arbiter git remote (default: per-repo/global defaultArbiter)',
		)
		.option(
			'--merge',
			'integrate in merge mode this invocation (mutually exclusive with --propose; overrides config)',
		)
		.option(
			'--propose',
			'integrate in propose mode this invocation (default; mutually exclusive with --merge; overrides config)',
		)
		.option('--agent-cmd <cmd>', 'command to run the agent on the slice prompt')
		.option(
			'--model <id>',
			'model the agent runs on (routing intent; resolved flag > env > per-repo > global > default)',
		)
		.option(
			'--harness <adapter>',
			'harness adapter that launches the agent: null (default, shells out to agentCmd) or pi (the pi CLI)',
		)
		.option(
			'--pi-bin <path>',
			'pi CLI binary the pi harness invokes (default: pi on PATH)',
		)
		.option(
			'--watch',
			"stream the agent's high-signal events live by tailing the pi session log (requires harness: pi; READ-ONLY observer — does not change outcome/gate/git)",
		)
		.action(async (rawSlug: string | undefined, flags: DoFlags) => {
			if (rawSlug === undefined) {
				// Auto-pick (no arg) is the do-autopick slice; this slice is the
				// single-named-item, in-place path only.
				console.error(
					'error: `do` needs an item to do (a <slug>). Auto-pick (no arg) ' +
						'is not yet wired (the do-autopick slice).',
				);
				process.exit(1);
			}
			const cwd = process.cwd();
			const global = loadConfig(flags.config);
			// Resolve the integration mode at integrate-time, highest first:
			//   --merge/--propose flag > per-repo .agent-runner.json > global > default.
			// (Same chain `complete` uses — `do` is the autonomous twin.)
			let flagMode;
			try {
				flagMode = integrationFromFlags(flags);
			} catch (err) {
				console.error(
					`error: ${err instanceof Error ? err.message : String(err)}`,
				);
				process.exit(1);
			}
			const resolved = resolveRepoConfig({
				repoPath: cwd,
				global,
				flags: flagMode ? {integration: flagMode} : {},
			});
			if (resolved.message) {
				console.error(`>> ${resolved.message}`);
			}
			const config = resolved.config;
			// The null adapter shells out to agentCmd, so it is required there; the
			// pi adapter invokes the pi CLI directly and does not consume agentCmd.
			if (config.harness !== 'pi' && config.agentCmd.trim() === '') {
				console.error(
					'error: no agentCmd configured — set `agentCmd` in config or pass --agent-cmd.',
				);
				process.exit(1);
			}
			const harness = createHarness({
				harness: config.harness,
				piBin: config.piBin,
			});
			const result = await performDo({
				arg: rawSlug,
				cwd,
				arbiter: flags.arbiter ?? config.defaultArbiter,
				integration: config.integration,
				verify: config.verify,
				provider: config.provider,
				harness,
				agentCmd: config.agentCmd,
				model: config.model,
				// `--watch`: tail the pi session log live (pi harness only; the
				// performDo guard errors clearly on any other adapter). READ-ONLY.
				watch: flags.watch === true,
				color: shouldUseColor(process.stdout),
				note: (message) => console.error(`>> ${message}`),
				noteBlock: (message) => console.error(message),
			});
			if (result.exitCode !== 0) {
				console.error(`error: ${result.message}`);
			}
			process.exit(result.exitCode);
		});

	program
		.command('gc')
		.description(
			'Re-apply the provably-safe deletion predicate (ADR \u00a74) across every job worktree under workspacesDir/work/*: reap the provably-safe ones (clean tree AND branch tip reachable on the arbiter \u2014 merged or pushed) via git worktree remove (+ prune, never rm -rf), and report each RETAINED one with a reason. The catch-up for when end-of-job auto-reap did not run (runner crash/kill). --force overrides the predicate (discards un-saved work) \u2014 loud, never default.',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--workspace <dir>',
			'execution working area to sweep (default: workspacesDir / ~/.agent-runner)',
		)
		.option(
			'--force',
			'OVERRIDE the predicate: remove worktrees even with un-saved work (requires --yes; never the default)',
		)
		.option('--yes', 'confirm a destructive --force sweep non-interactively')
		.option('--json', 'output the raw result as JSON')
		.action((flags: GcFlags) => {
			const config = resolveGlobalConfig(loadConfig(flags.config), {});
			const workspacesDir = flags.workspace ?? config.workspacesDir;

			// `--force` discards un-saved work, so it is gated behind an explicit
			// confirmation (`--yes`) — loud + intentional, NEVER the default (ADR §4).
			if (flags.force && !flags.yes) {
				console.error(
					'refusing to --force without --yes: this DISCARDS un-saved work in ' +
						'retained worktrees (commits not on the arbiter, dirty trees). ' +
						'Re-run with `gc --force --yes` to confirm.',
				);
				process.exit(1);
			}
			if (flags.force) {
				console.error(
					'>> --force: OVERRIDING the deletion-safety predicate; un-saved work ' +
						'in retained worktrees will be DISCARDED.',
				);
			}

			const result = gc({
				workspacesDir,
				force: flags.force === true,
				note: (message) => console.error(`>> ${message}`),
			});

			if (flags.json) {
				console.log(JSON.stringify(result, null, 2));
				return;
			}
			for (const reaped of result.reaped) {
				const how = reaped.forced
					? 'FORCED (discarded un-saved work)'
					: (reaped.verdict.reachableVia ?? 'safe');
				console.log(`  [reaped]   ${reaped.slug} \u2014 ${how}`);
			}
			for (const retained of result.retained) {
				console.log(
					`  [retained] ${retained.slug} \u2014 ${RETAIN_REASON_TEXT[retained.reason]}`,
				);
			}
			console.log(
				`Summary: ${result.reaped.length} reaped, ${result.retained.length} retained.`,
			);
		});

	program
		.command('status')
		.description(
			'Read-only operational dashboard of JOBS (distinct from scan’s backlog queue): list every job under workspacesDir/work/* from its .agent-runner-job.json record + worktree state, grouped active (running + alive) vs failed/retained (needs-attention with its reason, a crashed running-but-dead job, or a done-but-un-reaped one). Liveness comes from the harness seam (PID/session), NOT mtime. Never claims/runs/moves/deletes (deletion is gc).',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--workspace <dir>',
			'execution working area to inspect (default: workspacesDir / ~/.agent-runner)',
		)
		.option(
			'--arbiter-remote <name>',
			`the current repo's arbiter remote to report on (folds in the old \`arbiter status\`; default: ${DEFAULT_ARBITER_REMOTE})`,
		)
		.option('--no-arbiter', "skip the current repo's arbiter section")
		.option('--json', 'output the raw report as JSON')
		.action(async (flags: StatusFlags) => {
			const config = resolveGlobalConfig(loadConfig(flags.config), {});
			const workspacesDir = flags.workspace ?? config.workspacesDir;
			// Surface the folder-native needs-attention set (ADR §12) from each
			// REGISTERED HUB MIRROR (the registry), read from its bare `main` ref
			// through the read seam (mirrors have no working tree).
			const mirrorPaths = listMirrors({workspacesDir}).map((m) => m.path);
			// Fold in the current repo's arbiter state (the old `arbiter status`, ADR
			// §1/§7) unless --no-arbiter. Read-only; tolerates not being in a repo.
			const arbiter =
				flags.noArbiter === true
					? undefined
					: arbiterStatus({
							cwd: process.cwd(),
							remote: flags.arbiterRemote ?? DEFAULT_ARBITER_REMOTE,
						});
			const report = await status({workspacesDir, mirrorPaths, arbiter});
			if (flags.json) {
				console.log(JSON.stringify(report, null, 2));
			} else {
				console.log(formatStatus(report));
			}
		});

	program
		.command('return <slug>')
		.description(
			'Return a resolved needs-attention item to the backlog for re-claiming (ADR §12): git mv work/needs-attention/<slug>.md → work/backlog/<slug>.md and commit it. The clean re-queue once a human has resolved the cause, so items do not rot. The recorded reason stays in the body as a durable note.',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--cwd <dir>',
			'the repo/working clone whose work/ tree holds the item (default: cwd)',
		)
		.option(
			'--arbiter <remote>',
			'also push the transition to this arbiter remote (like the done-move)',
		)
		.action((rawSlug: string, flags: ReturnFlags) => {
			// Slice-only command (§3a): accept bare + `slice:`, reject `prd:`. (This is
			// the `return` verb today; the `flag-cleanup-renames` sibling slice renames
			// it to `requeue` — the guard wiring carries over unchanged.)
			const slug = resolveSliceOnlySlug(rawSlug) as string;
			const cwd = flags.cwd ?? process.cwd();
			// Route the return-to-backlog re-queue THROUGH the ledger write seam's
			// transition (same seam the needs-attention move uses), not the helper.
			const result = ledgerWrite.applyReturnToBacklogTransition({
				cwd,
				slug,
				arbiter: flags.arbiter,
				note: (message) => console.error(`>> ${message}`),
			});
			if (!result.moved) {
				console.error(`error: ${result.reasonNotMoved}`);
				process.exit(1);
			}
			console.log(`Returned '${slug}' to backlog for re-claiming.`);
		});

	// The REGISTRY command group (ADR §1): the registered set of targets IS the
	// hub-mirror set on disk. `remote add --local` absorbs the old `arbiter init`;
	// `arbiter status` is folded into `status`. There is no standalone `arbiter`
	// command group, and no `roots`/`remotes` config field.
	const remote = program
		.command('remote')
		.description(
			'The registry: the registered set of targets IS the hub mirrors on disk under workspacesDir/repos/ (no roots/remotes config). add/rm/ls/find manage that set. `remote add --local` provisions a bare arbiter (absorbing `arbiter init`); `arbiter status` is folded into `status`.',
		);

	remote
		.command('add <target>')
		.description(
			'Register a target by creating its hub mirror (idempotent). <target> is the arbiter URL; with --local it is a WORKING REPO whose bare arbiter is provisioned under arbitersDir (~/git, precious DATA, NEVER ~/.agent-runner) and THAT arbiter is registered (absorbing `arbiter init`). The transport guard refuses registering one project (same host/org/name) under a second transport unless --force.',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option(
			'--local',
			'provision a local --bare arbiter from <target> (a working repo) and register it (absorbs `arbiter init`)',
		)
		.option(
			'--arbiter-remote <name>',
			`name of the arbiter remote to wire in the working repo on --local (default: ${DEFAULT_ARBITER_REMOTE})`,
		)
		.option(
			'--force',
			'register even though the same project is already registered under a different transport (anti-stranding guard override)',
		)
		.action((target: string, flags: RemoteAddFlags) => {
			const config = resolveGlobalConfig(loadConfig(flags.config), {});
			try {
				const result = remoteAdd({
					target,
					local: flags.local,
					workspacesDir: config.workspacesDir,
					arbitersDir: config.arbitersDir,
					arbiterRemote: flags.arbiterRemote ?? DEFAULT_ARBITER_REMOTE,
					force: flags.force,
					note: (message) => console.error(`>> ${message}`),
				});
				if (result.arbiter) {
					const a = result.arbiter;
					console.log(
						a.created
							? `Provisioned bare arbiter at ${a.path}`
							: `Arbiter already exists at ${a.path} (not clobbered)`,
					);
					console.log(`Wired remote '${a.remote}' -> ${a.url}`);
				}
				console.log(
					result.created
						? `Registered '${result.key}' (${result.transport}) — hub mirror at ${result.mirrorPath}`
						: `'${result.key}' already registered (mirror at ${result.mirrorPath})`,
				);
			} catch (err) {
				if (err instanceof RegistryError) {
					console.error(`error: ${err.message}`);
					process.exit(1);
				}
				throw err;
			}
		});

	remote
		.command('rm <target>')
		.description(
			'Delete a hub mirror by key (host/org/name) or origin URL. The ONLY mirror deleter — `gc` NEVER reaps mirrors. Plumbing tier.',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.action((target: string, flags: RemoteRmFlags) => {
			const config = resolveGlobalConfig(loadConfig(flags.config), {});
			const result = remoteRm({target, workspacesDir: config.workspacesDir});
			if (!result.removed) {
				console.error(`error: no registered mirror matches '${target}'.`);
				process.exit(1);
			}
			console.log(`Removed mirror '${result.key}' (${result.path}).`);
		});

	remote
		.command('ls')
		.description(
			'List every registered hub mirror with its origin URL + transport. The origin URL is read from each mirror (the key encoding is lossy — it drops scheme/transport), so it is authoritative, not reconstructed from the key.',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option('--json', 'output the raw list as JSON')
		.action((flags: RemoteLsFlags) => {
			const config = resolveGlobalConfig(loadConfig(flags.config), {});
			const mirrors = listMirrors({workspacesDir: config.workspacesDir});
			if (flags.json) {
				console.log(JSON.stringify(mirrors, null, 2));
				return;
			}
			if (mirrors.length === 0) {
				console.log(
					'No registered mirrors. Use `remote add <url>` or `remote find <folder>`.',
				);
				return;
			}
			for (const m of mirrors) {
				console.log(
					`${m.key}   ${m.transport}   ${m.originUrl ?? '(no origin)'}`,
				);
			}
		});

	remote
		.command('find <folder>')
		.description(
			'Discover work/-participating repos under <folder> (a populated work/backlog/), then toggle-add the chosen ones via `remote add`. Interactive multi-select by default; --yes adds ALL discovered repos non-interactively.',
		)
		.option('-c, --config <path>', 'config file path', defaultConfigPath())
		.option('--yes', 'add all discovered participating repos (no prompt)')
		.action(async (folder: string, flags: RemoteFindFlags) => {
			const config = resolveGlobalConfig(loadConfig(flags.config), {});
			const repos = findParticipatingRepos(folder);
			if (repos.length === 0) {
				console.log(`No work/-participating repos found under ${folder}.`);
				return;
			}
			const chosen = flags.yes ? repos : await promptMultiSelect(repos);
			if (chosen.length === 0) {
				console.log('Nothing selected; no mirrors added.');
				return;
			}
			for (const repoPath of chosen) {
				// Each discovered repo is registered as a LOCAL bare arbiter (it is a
				// working checkout on disk, not a remote URL) — the same path
				// `remote add --local` takes. The transport guard still applies.
				try {
					const result = remoteAdd({
						target: repoPath,
						local: true,
						workspacesDir: config.workspacesDir,
						arbitersDir: config.arbitersDir,
						arbiterRemote: DEFAULT_ARBITER_REMOTE,
						note: (message) => console.error(`>> ${message}`),
					});
					console.log(
						`${result.created ? 'Registered' : 'Already registered'} '${result.key}' (${repoPath}).`,
					);
				} catch (err) {
					if (err instanceof RegistryError) {
						console.error(`skipped ${repoPath}: ${err.message}`);
						continue;
					}
					throw err;
				}
			}
		});

	return program;
}

/**
 * A minimal interactive multi-select toggle for `remote find`: list the
 * discovered repos numbered, let the user type the numbers to add (space/comma
 * separated; `all` for everything; blank for none). A non-interactive (no TTY)
 * invocation selects nothing — use `--yes` to add all without a prompt.
 */
function promptMultiSelect(repos: string[]): Promise<string[]> {
	return new Promise((resolvePrompt) => {
		if (!process.stdin.isTTY) {
			resolvePrompt([]);
			return;
		}
		const rl = createInterface({input: process.stdin, output: process.stderr});
		process.stderr.write('Discovered work/-participating repos:\n');
		repos.forEach((repo, i) => {
			process.stderr.write(`  [${i + 1}] ${repo}\n`);
		});
		rl.question('Add which? (numbers, `all`, or blank for none) ', (answer) => {
			rl.close();
			const trimmed = answer.trim().toLowerCase();
			if (trimmed === '') {
				resolvePrompt([]);
				return;
			}
			if (trimmed === 'all') {
				resolvePrompt([...repos]);
				return;
			}
			const picks = new Set<string>();
			for (const token of trimmed.split(/[\s,]+/)) {
				const n = Number(token);
				if (Number.isInteger(n) && n >= 1 && n <= repos.length) {
					picks.add(repos[n - 1]);
				}
			}
			resolvePrompt([...picks]);
		});
	});
}

const program = buildProgram();
program.parseAsync(process.argv).catch((err: unknown) => {
	console.error(err instanceof Error ? err.message : String(err));
	process.exit(1);
});

import {readFileSync, existsSync} from 'node:fs';
import {join} from 'node:path';
import {mergeConfig, type Config, type PartialConfig} from './config.js';
import {envOverrides, type EnvMap} from './env-config.js';

/**
 * The per-repo config layer.
 *
 * A repo may commit a `.agent-runner.json` at its root. It travels WITH the repo
 * (it is committed) and overrides the global `~/.config/agent-runner/config.json`
 * FOR THAT REPO ONLY — so repo-local properties (how this repo integrates, its
 * acceptance `verify` gate, which remote arbitrates its claims) are agreed by all
 * collaborators and agents rather than living in one person's global config.
 *
 * Resolution is per-key, highest wins:
 *
 *   flag (where a command offers one) > ENV (AGENT_RUNNER_*) > per-repo file >
 *   global > built-in default
 *
 * The mechanism is multi-repo aware: each repo resolves against its OWN
 * `.agent-runner.json`, so repo A can be `merge` while repo B is `propose` in the
 * SAME run (see {@link resolveRepoConfig}).
 *
 * Only keys that are genuinely repo properties are honoured in the COMMITTED
 * per-repo file. Runner/host-only keys (`piBin`, `agentCmd`, `maxParallel`, …)
 * describe the runner or the host machine, NOT a single repo;
 * if present in a per-repo file they are ignored and reported with a clear
 * message ({@link loadRepoConfig}).
 *
 * The sharpened host-only principle (ADR §13): **host-only keys must come from a
 * per-machine source — a CLI flag, an `AGENT_RUNNER_*` env var, or the global
 * config file — NEVER the committed repo file.** The allow/reject split below
 * therefore governs ONLY the committed repo file; env (a per-machine source like
 * the global file / a flag) may set ANY key, host-only included (see
 * {@link envOverrides}).
 *
 * A repo with no `.agent-runner.json` resolves to exactly the global config —
 * behaviour is unchanged from before this layer existed.
 */

/** The conventional per-repo config filename, committed at the repo root. */
export const REPO_CONFIG_FILENAME = '.agent-runner.json';

/**
 * Config keys that are genuinely repo properties and so are honoured in a
 * per-repo `.agent-runner.json`. Deliberately a subset of {@link Config};
 * extend this list as more keys become legitimately repo-scoped.
 */
export const REPO_ALLOWED_KEYS = [
	'integration',
	'provider',
	'verify',
	'defaultArbiter',
	'allowAgents',
	// `model` (which model this repo's work runs on) and `harness` (which adapter)
	// are legitimate repo properties (ADR §13) — model is routing intent, not auth,
	// and a repo may prefer a given harness. `piBin`/`agentCmd` stay host-only
	// (machine paths/commands), so they are rejected below.
	'model',
	'harness',
] as const satisfies readonly (keyof Config)[];

/** A key honoured in a per-repo file. */
export type RepoAllowedKey = (typeof REPO_ALLOWED_KEYS)[number];

/**
 * Config keys that describe the RUNNER or the HOST machine, not a single repo,
 * and so are rejected (ignored + reported) in a per-repo file. These remain the
 * domain of the global config / CLI flags.
 */
export const REPO_REJECTED_KEYS = [
	'maxParallel',
	'perRepoMax',
	'agentCmd',
	// `piBin` is a machine PATH/command, not repo policy, so it is host-only and
	// rejected per-repo (ADR §13). It must come from a per-machine source — a
	// flag, an `AGENT_RUNNER_PI_BIN` env var, or the global file — never a
	// committed repo file. (`harness`, by contrast, is repo-appropriate and so is
	// deliberately NOT rejected.)
	'piBin',
	// Reserved/future host-only keys callers may name; rejected proactively so a
	// typo or a copy-pasted global config never silently leaks host policy into a
	// repo. (`humanWorktreesDir` is a planned host-only path.)
	'humanWorktreesDir',
] as const;

/** A key rejected from a per-repo file. */
export type RepoRejectedKey = (typeof REPO_REJECTED_KEYS)[number];

const ALLOWED_SET = new Set<string>(REPO_ALLOWED_KEYS);

/** The path to a repo's `.agent-runner.json` (repo root + filename). */
export function repoConfigPath(repoPath: string): string {
	return join(repoPath, REPO_CONFIG_FILENAME);
}

/** The result of reading (and filtering) a repo's `.agent-runner.json`. */
export interface LoadedRepoConfig {
	/** Where we looked (whether or not the file exists). */
	path: string;
	/**
	 * Only the repo-appropriate keys found in the file, ready to layer over the
	 * global config. Unknown and rejected keys are NOT present here.
	 */
	config: PartialConfig;
	/**
	 * Runner/host-only keys that WERE present in the file and were ignored. Empty
	 * when nothing was rejected.
	 */
	rejected: string[];
	/**
	 * A clear, human-facing message naming the rejected keys and the file they
	 * came from. `undefined` when nothing was rejected.
	 */
	message?: string;
}

/**
 * Read a repo's `.agent-runner.json` and split it into the honoured subset and
 * the rejected runner/host-only keys. A missing file is not an error (the repo
 * simply resolves to the global config); invalid JSON is. Unknown keys are
 * silently dropped (neither honoured nor reported as rejected). Only keys in
 * {@link REPO_ALLOWED_KEYS} are carried into `config`.
 */
export function loadRepoConfig(repoPath: string): LoadedRepoConfig {
	const path = repoConfigPath(repoPath);
	if (!existsSync(path)) {
		return {path, config: {}, rejected: []};
	}

	let raw: string;
	try {
		raw = readFileSync(path, 'utf8');
	} catch (err) {
		throw new Error(`Failed to read ${path}: ${(err as Error).message}`);
	}

	let parsed: Record<string, unknown>;
	try {
		parsed = JSON.parse(raw) as Record<string, unknown>;
	} catch (err) {
		throw new Error(`Invalid JSON in ${path}: ${(err as Error).message}`);
	}

	const config: PartialConfig = {};
	const rejected: string[] = [];
	for (const key of Object.keys(parsed)) {
		const value = parsed[key];
		if (value === undefined) {
			continue;
		}
		if (ALLOWED_SET.has(key)) {
			// Type matches by construction: key ∈ REPO_ALLOWED_KEYS ⊂ keyof Config.
			(config as Record<string, unknown>)[key] = value;
		} else if (isRejectedKey(key)) {
			rejected.push(key);
		}
		// else: unknown key ⇒ silently ignored.
	}

	const message =
		rejected.length > 0
			? `Ignoring runner/host-only key(s) in ${REPO_CONFIG_FILENAME} ` +
				`(${path}): ${rejected.join(', ')}. ` +
				`These describe the runner/host, not a single repo, and belong in ` +
				`the global config or a CLI flag.`
			: undefined;

	return {path, config, rejected, ...(message ? {message} : {})};
}

function isRejectedKey(key: string): boolean {
	return (REPO_REJECTED_KEYS as readonly string[]).includes(key);
}

/** Inputs to {@link resolveRepoConfig}. */
export interface ResolveRepoConfigOptions {
	/** Absolute path to the repo root (where `.agent-runner.json` would live). */
	repoPath: string;
	/**
	 * The fully-resolved GLOBAL config (already merged over built-in defaults,
	 * e.g. via {@link mergeConfig} / `loadConfig`). The per-repo file and any
	 * flags layer OVER this; it provides the global + default layers of the
	 * precedence chain.
	 */
	global: Config;
	/**
	 * Command-level flag overrides (where a command offers one). These sit at the
	 * TOP of the precedence chain: flag > env > per-repo > global > default. Only
	 * keys a command actually exposes need appear here.
	 */
	flags?: PartialConfig;
	/**
	 * The raw environment map the `AGENT_RUNNER_*` layer is read from (defaults to
	 * `process.env`). Env sits ABOVE the per-repo file and BELOW a flag, and — as
	 * a per-machine source — may set ANY key, host-only included (it is NOT subject
	 * to the per-repo allow/reject split). Injectable so tests need not mutate the
	 * real `process.env`.
	 */
	env?: EnvMap;
}

/** The effective config for one repo, plus any rejected-key diagnostics. */
export interface ResolvedRepoConfig {
	/** The layered, effective {@link Config} for this repo. */
	config: Config;
	/** Runner/host-only keys ignored in this repo's file (see {@link loadRepoConfig}). */
	rejected: string[];
	/** Clear message for the rejected keys, if any. */
	message?: string;
}

/**
 * Resolve the effective config for ONE repo by layering, per key:
 *
 *   flag > ENV (AGENT_RUNNER_*) > per-repo `.agent-runner.json` > global >
 *   built-in default
 *
 * The `global` argument already carries the global + default layers (it is the
 * output of `loadConfig`/`mergeConfig`). We layer the repo's honoured keys over
 * it, then the `AGENT_RUNNER_*` env layer over that (env may set host-only keys
 * the per-repo file rejected — it is a per-machine source), then any flags on
 * top. The shared `global` object is never mutated, so calling this once per repo
 * in a multi-repo run yields INDEPENDENT results — repo A can be `merge` while
 * repo B is `propose` in the same run.
 *
 * A repo with no `.agent-runner.json` (and no env) resolves to exactly `global`
 * (unchanged behaviour).
 */
export function resolveRepoConfig(
	options: ResolveRepoConfigOptions,
): ResolvedRepoConfig {
	const {repoPath, global, flags, env} = options;
	const repo = loadRepoConfig(repoPath);
	// mergeConfig copies `global` (spreads DEFAULT_CONFIG then assigns) so the
	// shared global object is never mutated. Layer per-repo, then env (a
	// per-machine source — may set host-only keys), then flags on top.
	const config = mergeConfig({
		...global,
		...repo.config,
		...envOverrides(env),
		...(flags ?? {}),
	});
	return {
		config,
		rejected: repo.rejected,
		...(repo.message ? {message: repo.message} : {}),
	};
}

import type {Config, PartialConfig} from './config.js';

/**
 * The environment-variable config layer.
 *
 * A per-machine context (a CI job, a developer's shell) can set ANY {@link Config}
 * key via an `AGENT_RUNNER_*` environment variable WITHOUT committing a file —
 * including the host-only keys (`piBin`, `agentCmd`, …) that the per-repo
 * `.agent-runner.json` deliberately rejects.
 *
 * Env is a legitimate *per-machine source* — exactly like a CLI flag or the
 * global `~/.config/agent-runner/config.json` — so it is NOT subject to the
 * per-repo allow/reject split (that split only governs the *committed repo
 * file*). This is the sharpened host-only principle (ADR §13): host-only keys
 * must come from a per-machine source (flag, env, or global file), never the
 * committed repo file; env is simply the per-machine source CI actually has
 * without writing a file.
 *
 * Resolution chain (highest wins):
 *
 *   flag > ENV (AGENT_RUNNER_*) > per-repo > global > built-in default
 *
 * Naming: `AGENT_RUNNER_<SCREAMING_SNAKE(key)>` (mechanical camelCase →
 * SCREAMING_SNAKE, prefixed with `AGENT_RUNNER_` to match the binary). E.g.
 * `AGENT_RUNNER_AGENT_CMD`, `AGENT_RUNNER_PI_BIN`, `AGENT_RUNNER_DEFAULT_ARBITER`,
 * `AGENT_RUNNER_PER_REPO_MAX`.
 *
 * Each value is coerced per the key's type and a typo/invalid value FAILS LOUDLY
 * (never silently ignored) with a message naming the offending variable.
 */

/** The shared `AGENT_RUNNER_` prefix on every env config variable. */
export const ENV_PREFIX = 'AGENT_RUNNER_';

/** How a key's env value is coerced from its raw string. */
type Coercion =
	| 'string'
	| 'boolean'
	| 'number'
	| 'list'
	| {enum: readonly string[]};

/**
 * The coercion to apply per {@link Config} key. The source of truth for which
 * env vars exist and how their raw strings become typed values. EVERY `Config`
 * key appears here (host-only included) — env is a per-machine source, so no key
 * is off-limits. Keys not listed have no env var.
 */
const KEY_COERCIONS: {[K in keyof Config]-?: Coercion} = {
	allowAgents: 'boolean',
	maxParallel: 'number',
	perRepoMax: 'number',
	defaultArbiter: 'string',
	workspacesDir: 'string',
	arbitersDir: 'string',
	humanWorktreesDir: 'string',
	integration: {enum: ['propose', 'merge']},
	provider: {enum: ['none', 'github']},
	agentCmd: 'string',
	model: 'string',
	harness: {enum: ['null', 'pi']},
	piBin: 'string',
	verify: 'list',
};

/** camelCase config key → SCREAMING_SNAKE (`perRepoMax` → `PER_REPO_MAX`). */
function screamingSnake(key: string): string {
	return key.replace(/([a-z0-9])([A-Z])/g, '$1_$2').toUpperCase();
}

/** The `AGENT_RUNNER_*` env var name for a config key. */
export function envVarName(key: keyof Config): string {
	return ENV_PREFIX + screamingSnake(key);
}

/** A raw env map (defaults to `process.env`). */
export type EnvMap = Record<string, string | undefined>;

/**
 * Coerce a raw env string for one key, FAILING LOUDLY (with the offending var
 * name) on invalid input: booleans accept only `true`/`false`; numbers reject
 * NaN; enums must be in their union; list keys split on comma; strings verbatim.
 */
function coerceValue(
	varName: string,
	raw: string,
	coercion: Coercion,
): unknown {
	if (typeof coercion === 'object') {
		// Enum: validate against the union.
		if (!coercion.enum.includes(raw)) {
			throw new Error(
				`Invalid value for ${varName}: '${raw}'. ` +
					`Expected one of: ${coercion.enum.join(', ')}.`,
			);
		}
		return raw;
	}
	switch (coercion) {
		case 'string':
			return raw;
		case 'boolean':
			if (raw === 'true') {
				return true;
			}
			if (raw === 'false') {
				return false;
			}
			throw new Error(
				`Invalid boolean for ${varName}: '${raw}'. Expected 'true' or 'false'.`,
			);
		case 'number': {
			const n = Number(raw);
			if (raw.trim() === '' || Number.isNaN(n)) {
				throw new Error(
					`Invalid number for ${varName}: '${raw}'. Expected a numeric value.`,
				);
			}
			return n;
		}
		case 'list':
			// Split on comma (cross-platform; not `:`), trimming each entry. An empty
			// string ⇒ an empty list (an explicit "clear" of a list key).
			return raw
				.split(',')
				.map((s) => s.trim())
				.filter((s) => s !== '');
	}
}

/**
 * Read the `AGENT_RUNNER_*` env layer into a {@link PartialConfig}. Only vars
 * actually present (and non-`undefined`) contribute, so absent env ⇒ `{}` and
 * built-in floors/defaults are untouched. Each present var is coerced per its
 * key's type; an invalid value throws LOUDLY naming the variable.
 *
 * Env may set ANY key — host-only included — because env is a per-machine
 * source, NOT the committed repo file (see this module's doc + ADR §13).
 */
export function envOverrides(env: EnvMap = process.env): PartialConfig {
	const overrides: PartialConfig = {};
	for (const key of Object.keys(KEY_COERCIONS) as (keyof Config)[]) {
		const varName = envVarName(key);
		const raw = env[varName];
		if (raw === undefined) {
			continue;
		}
		const value = coerceValue(varName, raw, KEY_COERCIONS[key]);
		// Type matches by construction: each coercion yields the key's value type.
		(overrides as Record<string, unknown>)[key] = value;
	}
	return overrides;
}

import {describe, it, expect, beforeEach, afterEach} from 'vitest';
import {writeFileSync, mkdirSync, existsSync} from 'node:fs';
import {join} from 'node:path';
import {performDo, type DoAgentRunner} from '../src/do.js';
import {performComplete} from '../src/complete.js';
import {performClaim} from '../src/claim-cas.js';
import {
	makeScratch,
	seedRepoWithArbiter,
	existsOnArbiterMain,
	gitEnv,
	gitIn,
	type Scratch,
} from './helpers/gitRepo.js';

/**
 * `do <slug>` (in-place form) tests — the per-repo, in-place WORKER (the CI
 * command) that COMPOSES `start` + (autonomous agent run) + `complete`, guarded
 * by a dirty-tree refusal. House style: a throwaway checkout + a local `--bare`
 * arbiter + a STUBBED agent (the injected `agentRunner` edits files directly,
 * never a real harness). It drives real git + writes `main` (the autonomous
 * needs-attention surfacing), so it lives in the non-parallel project.
 */

let scratch: Scratch;
beforeEach(() => {
	scratch = makeScratch('agent-runner-do-');
});
afterEach(() => {
	scratch.cleanup();
});

const ARBITER = 'arbiter';
const PASS = 'exit 0';
const FAIL = 'exit 1';

function currentBranch(repo: string): string {
	return gitIn(['rev-parse', '--abbrev-ref', 'HEAD'], repo).trim();
}

/** A stubbed agent that edits a file (so the commit is non-empty) and succeeds. */
const editingAgent: DoAgentRunner = ({cwd}) => {
	writeFileSync(join(cwd, 'agent-output.txt'), 'work done\n');
	return {ok: true};
};

/** Seed a `work/prd/<slug>.md` in the checkout's working tree (for prd: tests). */
function seedPrd(repo: string, slug: string): void {
	const dir = join(repo, 'work', 'prd');
	mkdirSync(dir, {recursive: true});
	writeFileSync(
		join(dir, `${slug}.md`),
		['---', `title: ${slug}`, `slug: ${slug}`, '---', '', '# PRD', ''].join(
			'\n',
		),
	);
	// Commit it so the PRD lives on main (and survives the work-branch cut).
	gitIn(['add', '-A'], repo);
	gitIn(['commit', '-q', '-m', `prd: ${slug}`], repo);
	gitIn(['push', '-q', ARBITER, 'main'], repo);
}

describe('do <slug> — in-place happy path → exit', () => {
	it('refuses-on-dirty? no; claims + onboards + runs agent + gates + integrates in-place + exits', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});

		expect(result.exitCode).toBe(0);
		expect(result.outcome).toBe('completed');
		expect(result.slug).toBe('alpha');

		// merge mode → the work landed on the arbiter's main, in done/.
		expect(existsOnArbiterMain(repo, 'done', 'alpha')).toBe(true);
		expect(existsOnArbiterMain(repo, 'in-progress', 'alpha')).toBe(false);
		expect(existsOnArbiterMain(repo, 'backlog', 'alpha')).toBe(false);

		// The agent's edit landed (the runner committed it with the done-move).
		expect(
			gitIn(['cat-file', '-e', 'arbiter/main:agent-output.txt'], repo),
		).toBe('');

		// Like `complete`: switched back to main, branch tidied (provably on arbiter).
		expect(currentBranch(repo)).toBe('main');
		expect(gitIn(['branch', '--list', 'work/alpha'], repo).trim()).toBe('');
	});

	it('the AGENT does no git — the runner owns claim + done-move + commit', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		// An agent that ASSERTS the tree is already on the work branch + claimed
		// (the runner onboarded) and only edits code.
		const assertingAgent: DoAgentRunner = ({cwd, slug}) => {
			expect(currentBranch(cwd)).toBe(`work/${slug}`);
			// in-progress (claimed) in the tree; the agent never moved it.
			expect(existsSync(join(cwd, 'work', 'in-progress', `${slug}.md`))).toBe(
				true,
			);
			writeFileSync(join(cwd, 'agent-output.txt'), 'work\n');
			return {ok: true};
		};
		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			agentRunner: assertingAgent,
			env: gitEnv(),
		});
		expect(result.outcome).toBe('completed');
	});
});

describe('do <slug> — dirty-tree refusal (ar-run.sh guard)', () => {
	it('refuses on an unstaged dirty tree, claiming nothing', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		writeFileSync(join(repo, 'README.md'), '# project DIRTY\n');

		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});

		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('refused');
		expect(result.message).toMatch(/dirty/i);
		// Nothing claimed; still in backlog; still on main.
		expect(existsOnArbiterMain(repo, 'backlog', 'alpha')).toBe(true);
		expect(existsOnArbiterMain(repo, 'in-progress', 'alpha')).toBe(false);
		expect(currentBranch(repo)).toBe('main');
	});

	it('refuses on a staged-but-uncommitted dirty tree', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		writeFileSync(join(repo, 'staged.txt'), 'staged\n');
		gitIn(['add', 'staged.txt'], repo);

		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});
		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('refused');
		expect(existsOnArbiterMain(repo, 'backlog', 'alpha')).toBe(true);
	});
});

describe('do <slug> — lost claim race is skipped cleanly', () => {
	it('skips an item already claimed by someone else (no work branch, no agent)', async () => {
		const seeded = seedRepoWithArbiter(scratch.root, ['solo']);
		const repo = seeded.repo;
		// Another claimer wins first from a separate clone.
		const other = seeded.clone('other');
		const won = await performClaim({
			slug: 'solo',
			cwd: other,
			arbiter: ARBITER,
			env: gitEnv(),
		});
		expect(won.exitCode).toBe(0);

		let agentRan = false;
		const result = await performDo({
			arg: 'solo',
			cwd: repo,
			arbiter: ARBITER,
			verify: PASS,
			agentRunner: () => {
				agentRan = true;
				return {ok: true};
			},
			env: gitEnv(),
		});

		// start refuses an already-in-progress item (folder-based) → do reports the
		// lost/skip cleanly, runs no agent, creates no work branch.
		expect(result.exitCode).not.toBe(0);
		expect(['lost', 'refused']).toContain(result.outcome);
		expect(agentRan).toBe(false);
		expect(gitIn(['branch', '--list', 'work/solo'], repo).trim()).toBe('');
		expect(currentBranch(repo)).toBe('main');
	});

	it('a genuine two-doer race: the loser skips, the winner completes', async () => {
		const seeded = seedRepoWithArbiter(scratch.root, ['race']);
		const a = seeded.clone('a');
		const b = seeded.clone('b');

		const [ra, rb] = await Promise.all([
			performDo({
				arg: 'race',
				cwd: a,
				arbiter: ARBITER,
				integration: 'merge',
				verify: PASS,
				agentRunner: editingAgent,
				env: gitEnv(),
			}),
			performDo({
				arg: 'race',
				cwd: b,
				arbiter: ARBITER,
				integration: 'merge',
				verify: PASS,
				agentRunner: editingAgent,
				env: gitEnv(),
			}),
		]);

		const outcomes = [ra.outcome, rb.outcome].sort();
		// Exactly one completes; the other skips (lost/contended/refused).
		const completedCount = [ra, rb].filter(
			(r) => r.outcome === 'completed',
		).length;
		expect(completedCount).toBe(1);
		expect(outcomes).not.toEqual(['completed', 'completed']);
		// The item is done on the arbiter exactly once.
		expect(existsOnArbiterMain(a, 'done', 'race')).toBe(true);
	});
});

describe('do <slug> — red gate routes to needs-attention via the seam (AUTONOMOUS surfacing)', () => {
	it('a red gate surfaces the stuck item ON THE ARBITER main (not local-only)', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);

		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: FAIL,
			agentRunner: editingAgent,
			env: gitEnv(),
		});

		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('needs-attention');

		// CRITICAL — `do` is autonomous: the stuck state is SURFACED ON MAIN (the
		// mode-M cherry-pick of the move-only commit), so scan/status/another
		// machine can see it. A `complete` (human) call without surfaceArbiter
		// would leave main showing in-progress; `do` MUST surface it.
		expect(existsOnArbiterMain(repo, 'needs-attention', 'alpha')).toBe(true);
		expect(existsOnArbiterMain(repo, 'in-progress', 'alpha')).toBe(false);
		expect(existsOnArbiterMain(repo, 'done', 'alpha')).toBe(false);

		// Locally too, the item bounced to needs-attention/ with the reason.
		expect(existsSync(join(repo, 'work', 'needs-attention', 'alpha.md'))).toBe(
			true,
		);
		expect(existsSync(join(repo, 'work', 'in-progress', 'alpha.md'))).toBe(
			false,
		);
	});

	it('CONTRAST: human `complete` (no surfaceArbiter) routes LOCAL-ONLY — main still shows in-progress', async () => {
		// This locks the AUTONOMOUS-vs-HUMAN divergence the slice flags: `do` passes
		// the arbiter (surfaces on main); the human `complete` does NOT, so a red
		// gate leaves main showing in-progress (a human is right there). If someone
		// made `complete` always surface, this fails.
		const seeded = seedRepoWithArbiter(scratch.root, ['beta']);
		const repo = seeded.repo;
		const claim = await performClaim({
			slug: 'beta',
			cwd: repo,
			arbiter: ARBITER,
			env: gitEnv(),
		});
		expect(claim.exitCode).toBe(0);
		gitIn(['fetch', '-q', ARBITER], repo);
		gitIn(['switch', '-q', '-c', 'work/beta', `${ARBITER}/main`], repo);
		writeFileSync(join(repo, 'agent-output.txt'), 'work\n');

		const result = await performComplete({
			slug: 'beta',
			cwd: repo,
			arbiter: ARBITER,
			verify: FAIL,
			// NB: NO surfaceArbiter — the human path.
			env: gitEnv(),
		});
		expect(result.outcome).toBe('gate-failed');
		// Local-only: the item bounced locally, but main was NOT surfaced — it still
		// shows the in-progress claim (the human's, no cross-machine surfacing).
		expect(existsSync(join(repo, 'work', 'needs-attention', 'beta.md'))).toBe(
			true,
		);
		expect(existsOnArbiterMain(repo, 'in-progress', 'beta')).toBe(true);
		expect(existsOnArbiterMain(repo, 'needs-attention', 'beta')).toBe(false);
	});

	it('an agent failure before the gate surfaces agent-failed (item NOT moved to done)', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			verify: PASS,
			agentRunner: () => ({ok: false, detail: 'agent exploded'}),
			env: gitEnv(),
		});
		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('agent-failed');
		expect(result.message).toMatch(/exploded/);
		// Claimed + onboarded, but never integrated → not done on the arbiter.
		expect(existsOnArbiterMain(repo, 'done', 'alpha')).toBe(false);
	});
});

describe('do <slug> — --merge / --propose resolve at integrate-time', () => {
	it('--merge lands the work ON the arbiter main (done/)', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});
		expect(result.outcome).toBe('completed');
		expect(existsOnArbiterMain(repo, 'done', 'alpha')).toBe(true);
	});

	it('--propose (the CI default) pushes the work branch + does NOT auto-merge the work to main (CI equivalence to ar-run.sh --propose)', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);

		const result = await performDo({
			arg: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'propose',
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});
		expect(result.exitCode).toBe(0);
		expect(result.outcome).toBe('completed');

		// propose: the work CODE is on a PUSHED branch awaiting review, NOT merged
		// to main. The CLAIM move IS on main (the item is in-progress, not done),
		// but the agent's work has not auto-landed.
		expect(existsOnArbiterMain(repo, 'in-progress', 'alpha')).toBe(true);
		expect(existsOnArbiterMain(repo, 'done', 'alpha')).toBe(false);
		gitIn(['fetch', '-q', ARBITER], repo);
		// The agent's edit is NOT on main (no auto-merge in propose).
		const onMain = gitIn(
			['ls-tree', 'arbiter/main', 'agent-output.txt'],
			repo,
		).trim();
		expect(onMain).toBe('');
		// The work branch was pushed to the arbiter (the safety-bearing step).
		expect(
			gitIn(
				['rev-parse', '--verify', '--quiet', 'arbiter/work/alpha'],
				repo,
			).trim(),
		).not.toBe('');
	});
});

describe('do — slug resolution (§3a): bare / slice: / prd: + collision', () => {
	it('a bare slug resolves to the slice and builds it', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		const result = await performDo({
			arg: 'alpha', // bare → the slice
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});
		expect(result.outcome).toBe('completed');
		expect(result.slug).toBe('alpha');
	});

	it('an explicit slice:<slug> resolves to the slice and builds it', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		const result = await performDo({
			arg: 'slice:alpha',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});
		expect(result.outcome).toBe('completed');
		expect(result.slug).toBe('alpha');
	});

	it('do prd:<slug> dispatches to the slicing path (a clear "not yet wired" stub)', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['alpha']);
		seedPrd(repo, 'somePrd');

		let agentRan = false;
		const result = await performDo({
			arg: 'prd:somePrd',
			cwd: repo,
			arbiter: ARBITER,
			verify: PASS,
			agentRunner: () => {
				agentRan = true;
				return {ok: true};
			},
			env: gitEnv(),
		});
		// Reaches the slicing-path entry, which is not built yet (autoslice-command).
		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('prd-not-wired');
		expect(result.slug).toBe('somePrd');
		expect(result.message).toMatch(/slic/i);
		// It dispatched to slicing — it did NOT build a slice / run the agent.
		expect(agentRan).toBe(false);
	});

	it('a bare slug that collides (a slice AND a PRD share it) ERRORS loudly', async () => {
		// Seed a slice `dup` AND a PRD `dup` → a bare `do dup` is ambiguous.
		const {repo} = seedRepoWithArbiter(scratch.root, ['dup']);
		seedPrd(repo, 'dup');

		const result = await performDo({
			arg: 'dup', // bare → ambiguous across namespaces
			cwd: repo,
			arbiter: ARBITER,
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});
		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('usage-error');
		expect(result.message).toMatch(/ambiguous/i);
		expect(result.message).toMatch(/slice:dup/);
		expect(result.message).toMatch(/prd:dup/);
		// Nothing was claimed — the collision halts before any git transition.
		expect(existsOnArbiterMain(repo, 'backlog', 'dup')).toBe(true);
		expect(existsOnArbiterMain(repo, 'in-progress', 'dup')).toBe(false);
	});

	it('an explicit slice:<slug> on a colliding slug is unambiguous (builds the slice)', async () => {
		const {repo} = seedRepoWithArbiter(scratch.root, ['dup']);
		seedPrd(repo, 'dup');

		const result = await performDo({
			arg: 'slice:dup', // explicit → no collision check, builds the slice
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			agentRunner: editingAgent,
			env: gitEnv(),
		});
		expect(result.outcome).toBe('completed');
		expect(result.slug).toBe('dup');
		expect(existsOnArbiterMain(repo, 'done', 'dup')).toBe(true);
	});
});

import {describe, it, expect, beforeEach, afterEach} from 'vitest';
import {
	mkdtempSync,
	rmSync,
	writeFileSync,
	mkdirSync,
	readFileSync,
	chmodSync,
} from 'node:fs';
import {tmpdir} from 'node:os';
import {join} from 'node:path';
import {DEFAULT_CONFIG, mergeConfig} from '../src/config.js';
import {
	REPO_ALLOWED_KEYS,
	REPO_REJECTED_KEYS,
	REPO_CONFIG_FILENAME,
	resolveRepoConfig,
} from '../src/repo-config.js';
import {
	NullHarness,
	substituteModel,
	MODEL_PLACEHOLDER,
} from '../src/harness.js';
import {PiHarness} from '../src/pi-harness.js';
import {makeScratch, type Scratch} from './helpers/gitRepo.js';

/**
 * The model-config slice (ADR §13): `model` is a first-class, harness-agnostic
 * routing intent carried through the harness seam. agent-runner decides WHICH
 * model; it NEVER touches auth/keys (those stay the harness's job). These tests
 * cover (1) the optional `model` config field, (2) its per-repo resolution chain
 * (flag > env > per-repo > global > default), (3) each adapter's injection (pi:
 * native `--model`; null/shell: `{model}` placeholder), and (4) the three shell
 * degradation cases.
 */

describe('config.model — optional, no default (unset is meaningful)', () => {
	it('is undefined by default (agent-runner forces no model)', () => {
		expect(DEFAULT_CONFIG.model).toBeUndefined();
		expect(mergeConfig({}).model).toBeUndefined();
	});

	it('is carried through mergeConfig when set', () => {
		expect(mergeConfig({model: 'anthropic/claude-sonnet-4'}).model).toBe(
			'anthropic/claude-sonnet-4',
		);
	});
});

describe('repo-config — model + harness allowed per-repo, piBin rejected', () => {
	let repo: string;

	beforeEach(() => {
		repo = mkdtempSync(join(tmpdir(), 'agent-runner-model-'));
	});
	afterEach(() => {
		rmSync(repo, {recursive: true, force: true});
	});

	function writeRepoConfig(value: unknown): void {
		writeFileSync(join(repo, REPO_CONFIG_FILENAME), JSON.stringify(value));
	}

	it('treats model + harness as repo-appropriate keys', () => {
		expect(REPO_ALLOWED_KEYS).toContain('model');
		expect(REPO_ALLOWED_KEYS).toContain('harness');
	});

	it('keeps piBin host-only (rejected per-repo)', () => {
		expect(REPO_REJECTED_KEYS).toContain('piBin');
		expect(REPO_REJECTED_KEYS).toContain('agentCmd');
		expect(REPO_ALLOWED_KEYS).not.toContain('piBin');
		expect(REPO_ALLOWED_KEYS).not.toContain('agentCmd');
	});

	it('honours model + harness from a per-repo file; rejects piBin (reported)', () => {
		writeRepoConfig({
			model: 'repo/model',
			harness: 'pi',
			piBin: '/leaked/pi',
		});
		const resolved = resolveRepoConfig({
			repoPath: repo,
			global: mergeConfig({}),
		});
		expect(resolved.config.model).toBe('repo/model');
		expect(resolved.config.harness).toBe('pi');
		// piBin from the committed repo file is ignored + reported.
		expect(resolved.config.piBin).toBeUndefined();
		expect(resolved.rejected).toContain('piBin');
		expect(resolved.message).toMatch(/piBin/);
	});

	it('resolves model: flag > env > per-repo > global > default (unset)', () => {
		// default: unset
		expect(
			resolveRepoConfig({repoPath: repo, global: mergeConfig({})}).config.model,
		).toBeUndefined();

		// global only
		expect(
			resolveRepoConfig({
				repoPath: repo,
				global: mergeConfig({model: 'global/m'}),
			}).config.model,
		).toBe('global/m');

		// per-repo beats global
		writeRepoConfig({model: 'repo/m'});
		expect(
			resolveRepoConfig({
				repoPath: repo,
				global: mergeConfig({model: 'global/m'}),
			}).config.model,
		).toBe('repo/m');

		// env beats per-repo + global
		expect(
			resolveRepoConfig({
				repoPath: repo,
				global: mergeConfig({model: 'global/m'}),
				env: {AGENT_RUNNER_MODEL: 'env/m'},
			}).config.model,
		).toBe('env/m');

		// flag beats everything
		expect(
			resolveRepoConfig({
				repoPath: repo,
				global: mergeConfig({model: 'global/m'}),
				env: {AGENT_RUNNER_MODEL: 'env/m'},
				flags: {model: 'flag/m'},
			}).config.model,
		).toBe('flag/m');
	});
});

describe('substituteModel — three shell degradation rules (ADR §13)', () => {
	it('rule 1: {model} present + model set ⇒ substitute (every occurrence)', () => {
		expect(substituteModel('agent --model {model}', 'my/model')).toBe(
			'agent --model my/model',
		);
		expect(substituteModel('a {model} b {model}', 'X')).toBe('a X b X');
	});

	it('rule 2: {model} present + model unset ⇒ clear error (never a literal {model})', () => {
		expect(() => substituteModel('agent --model {model}', undefined)).toThrow(
			/\{model\}/,
		);
		expect(() => substituteModel('agent --model {model}', '')).toThrow(
			/no model is configured/,
		);
	});

	it('rule 3: {model} absent ⇒ run command as-is (model routing offered, not forced)', () => {
		expect(substituteModel('agent --do-thing', 'my/model')).toBe(
			'agent --do-thing',
		);
		expect(substituteModel('agent --do-thing', undefined)).toBe(
			'agent --do-thing',
		);
	});

	it('exposes the {model} placeholder constant', () => {
		expect(MODEL_PLACEHOLDER).toBe('{model}');
	});
});

describe('NullHarness — model injection via {model} placeholder', () => {
	let scratch: Scratch;
	beforeEach(() => {
		scratch = makeScratch('agent-runner-nullmodel-');
	});
	afterEach(() => {
		scratch.cleanup();
	});

	it('substitutes {model} in the command and records the substituted command', () => {
		const harness = new NullHarness();
		const out = join(scratch.root, 'model.txt');
		const result = harness.launch({
			dir: scratch.root,
			slug: 'feat',
			command: `printf '%s' '{model}' > ${JSON.stringify(out)}`,
			model: 'my/model',
		});
		expect(result.ok).toBe(true);
		expect(readFileSync(out, 'utf8')).toBe('my/model');
		// The recorded command carries the substituted value, not the placeholder.
		expect(result.record.command).toContain('my/model');
		expect(result.record.command).not.toContain(MODEL_PLACEHOLDER);
	});

	it('errors clearly when {model} is present but no model is configured', () => {
		const harness = new NullHarness();
		expect(() =>
			harness.launch({
				dir: scratch.root,
				slug: 'feat',
				command: 'agent --model {model}',
			}),
		).toThrow(/\{model\}/);
	});

	it('runs the command as-is when {model} is absent (model set or not)', () => {
		const harness = new NullHarness();
		const r1 = harness.launch({
			dir: scratch.root,
			slug: 'feat',
			command: 'true',
			model: 'my/model',
		});
		expect(r1.ok).toBe(true);
		expect(r1.record.command).toBe('true');
		const r2 = harness.launch({
			dir: scratch.root,
			slug: 'feat',
			command: 'true',
		});
		expect(r2.ok).toBe(true);
	});
});

describe('PiHarness — native --model injection (stubbed pi CLI)', () => {
	let scratch: Scratch;
	beforeEach(() => {
		scratch = makeScratch('agent-runner-pimodel-');
	});
	afterEach(() => {
		scratch.cleanup();
	});

	/** A pi stub that records the args it was invoked with. */
	function writePiStub(): {bin: string; argsFile: string} {
		const bin = join(scratch.root, 'pi-stub.sh');
		const argsFile = join(scratch.root, 'pi-args.txt');
		const script = [
			'#!/usr/bin/env bash',
			`printf '%s\\n' "$@" > ${JSON.stringify(argsFile)}`,
			'session_dir=""',
			'prev=""',
			'for a in "$@"; do',
			'  if [ "$prev" = "--session-dir" ]; then session_dir="$a"; fi',
			'  prev="$a"',
			'done',
			'if [ -n "$session_dir" ]; then mkdir -p "$session_dir"; fi',
			'cat > /dev/null',
			'exit 0',
		].join('\n');
		writeFileSync(bin, script + '\n');
		chmodSync(bin, 0o755);
		return {bin, argsFile};
	}

	it('passes --model <model> natively when model is set', () => {
		const stub = writePiStub();
		const harness = new PiHarness({piBin: stub.bin});
		const dir = join(scratch.root, 'wt');
		mkdirSync(dir, {recursive: true});
		harness.launch({
			dir,
			slug: 'feat',
			command: 'ignored',
			model: 'a/b',
			prompt: 'p',
		});
		const args = readFileSync(stub.argsFile, 'utf8').split('\n');
		expect(args).toContain('--model');
		expect(args).toContain('a/b');
		// --model appears BEFORE --print (the native model flag layers in first).
		expect(args.indexOf('--model')).toBeLessThan(args.indexOf('--print'));
	});

	it('passes NO --model when model is unset', () => {
		const stub = writePiStub();
		const harness = new PiHarness({piBin: stub.bin});
		const dir = join(scratch.root, 'wt');
		mkdirSync(dir, {recursive: true});
		harness.launch({dir, slug: 'feat', command: 'ignored', prompt: 'p'});
		const args = readFileSync(stub.argsFile, 'utf8').split('\n');
		expect(args).not.toContain('--model');
	});

	it('still honours operator extraArgs alongside the native --model', () => {
		const stub = writePiStub();
		const harness = new PiHarness({
			piBin: stub.bin,
			extraArgs: ['--flag', 'value'],
		});
		const dir = join(scratch.root, 'wt');
		mkdirSync(dir, {recursive: true});
		harness.launch({
			dir,
			slug: 'feat',
			command: 'ignored',
			model: 'a/b',
			prompt: 'p',
		});
		const args = readFileSync(stub.argsFile, 'utf8');
		expect(args).toContain('--model');
		expect(args).toContain('a/b');
		expect(args).toContain('--flag');
		expect(args).toContain('value');
	});
});

